questions.questionText:
What is the output of this code?

console.log(x);
var x = 5;
console.log(y);
let y = 10;

What is the output?

console.log(typeof []);
console.log(Array.isArray([]));

What is the output?

const a = [1, 2, 3];
const b = a;
b.push(4);
console.log(a);

What is the output?

console.log('5' + 3);
console.log('5' - 3);

What is the output?

console.log(Boolean(' '));
console.log(Boolean(''));

What is the correct order of execution for the following?

setTimeout(() => console.log('A'), 0);
Promise.resolve().then(() => console.log('B'));
console.log('C');

What is the output?

for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100);
}

What is the output?

const obj = { a: 1 };
const handler = {
  get(target, prop) {
    return prop in target ? target[prop] : 42;
  }
};
const proxy = new Proxy(obj, handler);
console.log(proxy.a, proxy.b);

What is the output?

console.log([...[1, 2], ...[3, 4]]);
console.log([...[1, 2], 5]);

What does the following code output?

let x = 10;
function outer() {
  let x = 20;
  function inner() {
    console.log(x);
  }
  return inner;
}
const fn = outer();
fn();

What is the output?

const p = new Promise((resolve, reject) => {
  reject(new Error('oops'));
  resolve('ok');
});
p.catch(e => console.log(e.message));

What does the following code log?

const arr = [3, 1, 2];
arr.sort();
console.log(arr);

What is the output?

const obj = { x: 1, y: 2 };
const { x, ...rest } = obj;
console.log(x, rest);

What does the following code output?

async function fetchData() {
  console.log('1');
  await Promise.resolve();
  console.log('2');
  await new Promise(r => setTimeout(r, 0));
  console.log('3');
}
fetchData();
console.log('4');

What is the output?

console.log(0.1 + 0.2 === 0.3);
console.log((0.1 + 0.2).toFixed(2));
console.log(Number.EPSILON);

What is the output?

const arr = [1, [2, [3, [4]]]];
console.log(arr.flat(2));
console.log(arr.flat(Infinity));

What is the output?

const [first, ...rest] = [1, 2, 3, 4];
console.log(first, rest);
function f(...args) {
  console.log(args.length);
}
f(1, 2, 3);

What is the output?

console.log(2 ** 3 ** 2);
console.log((2 ** 3) ** 2);
